const body = $input.first().json.body || $input.first().json;

// Split clientName into first / last
const fullName  = (body.clientName || '').trim();
const spaceIdx  = fullName.indexOf(' ');
const firstName = spaceIdx > -1 ? fullName.substring(0, spaceIdx) : fullName;
const lastName  = spaceIdx > -1 ? fullName.substring(spaceIdx + 1) : '';

const clientEmail = (body.clientEmail || '').trim().toLowerCase();
const service     = (body.service     || '').trim();
const date        = (body.date        || '').trim();
const time        = (body.time        || '').trim();
const bookingId   = String(body.bookingId || '').trim();
const amountPaid  = Number(body.amountPaid) || 0;

// Escape single quotes for SQL embedding
const esc = (s) => (s || '').replace(/'/g, "''");

const isFree       = amountPaid === 0;
const amountStr    = isFree ? 'Complimentary' : '$' + amountPaid;
const meetUrl      = 'https://meet.google.com/pcn-mqgs-jsj';
const bookUrl      = 'https://soul-synergy-hub.pages.dev/book';

// ── CLIENT CONFIRMATION EMAIL ──────────────────────────────────────────────
const clientHtml = [
  '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
  '<h2 style="color:#2D6A6A;margin-bottom:16px">\u2705 You\'re Booked, ' + firstName + '!</h2>',
  '<p style="line-height:1.7;color:#333">Hi ' + firstName + ',</p>',
  '<p style="line-height:1.7;color:#333">Your coaching session with Arushi is confirmed. Here are your details:</p>',
  '<div style="background:#f0f7f7;border-left:4px solid #2D6A6A;padding:16px 20px;margin:20px 0;border-radius:0 4px 4px 0">',
  '<table style="width:100%;border-collapse:collapse;font-size:14px;color:#333">',
  '<tr><td style="padding:6px 0;width:130px;color:#555"><strong>Service</strong></td><td style="padding:6px 0">' + service + '</td></tr>',
  '<tr><td style="padding:6px 0;color:#555"><strong>Date</strong></td><td style="padding:6px 0">' + date + '</td></tr>',
  '<tr><td style="padding:6px 0;color:#555"><strong>Time</strong></td><td style="padding:6px 0">' + time + ' EST</td></tr>',
  '<tr><td style="padding:6px 0;color:#555"><strong>Amount</strong></td><td style="padding:6px 0">' + amountStr + '</td></tr>',
  '</table>',
  '</div>',
  '<p style="line-height:1.7;color:#333;margin-bottom:8px"><strong>Join your session here:</strong></p>',
  '<div style="text-align:center;margin:24px 0">',
  '<a href="' + meetUrl + '" style="background:#2D6A6A;color:#fff;text-decoration:none;padding:14px 28px;border-radius:6px;font-size:15px;font-weight:600;display:inline-block">\uD83D\uDCF9 Join on Google Meet</a>',
  '</div>',
  '<p style="line-height:1.7;color:#555;font-size:13px;text-align:center">Or copy this link: <a href="' + meetUrl + '" style="color:#2D6A6A">' + meetUrl + '</a></p>',
  (isFree
    ? '<p style="line-height:1.7;color:#333">This is a complimentary discovery call — a chance for us to connect, explore what you\'re looking for, and see if we\'re a good fit. Come as you are.</p>'
    : '<p style="line-height:1.7;color:#333">To make the most of your session, find a quiet space, have a pen and paper nearby, and arrive a minute or two early.</p>'
  ),
  '<p style="line-height:1.7;color:#333">I\'m looking forward to our time together!</p>',
  '<p style="line-height:1.7;color:#333">Warmly,<br><strong>Arushi Bhardwaj</strong><br>SoulSynergy Coaching</p>',
  '<hr style="border:none;border-top:1px solid #eee;margin:24px 0">',
  '<p style="color:#999;font-size:12px">SoulSynergy Coaching &mdash; Uncover. Align. Achieve.</p>',
  '</div>'
].join('');

const clientPayload = JSON.stringify({
  from: 'SoulSynergy Coaching <onboarding@resend.dev>',
  to: [clientEmail],
  subject: '\u2705 Booking confirmed — ' + service + ' on ' + date,
  html: clientHtml
});

// ── ARUSHI NOTIFICATION EMAIL ──────────────────────────────────────────────
const arushiHtml = [
  '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
  '<h2 style="color:#2D6A6A;margin-bottom:16px">\uD83D\uDCC5 New Booking — ' + fullName + '</h2>',
  '<table style="width:100%;border-collapse:collapse;font-size:14px;color:#333;border:1px solid #ddd">',
  '<tr><td style="padding:10px 14px;background:#f5f5f5;width:130px"><strong>Client</strong></td><td style="padding:10px 14px;border-left:1px solid #ddd">' + fullName + ' &lt;' + clientEmail + '&gt;</td></tr>',
  '<tr><td style="padding:10px 14px;background:#f5f5f5"><strong>Service</strong></td><td style="padding:10px 14px;border-left:1px solid #ddd;border-top:1px solid #ddd">' + service + '</td></tr>',
  '<tr><td style="padding:10px 14px;background:#f5f5f5"><strong>Date</strong></td><td style="padding:10px 14px;border-left:1px solid #ddd;border-top:1px solid #ddd">' + date + '</td></tr>',
  '<tr><td style="padding:10px 14px;background:#f5f5f5"><strong>Time</strong></td><td style="padding:10px 14px;border-left:1px solid #ddd;border-top:1px solid #ddd">' + time + ' EST</td></tr>',
  '<tr><td style="padding:10px 14px;background:#f5f5f5"><strong>Amount Paid</strong></td><td style="padding:10px 14px;border-left:1px solid #ddd;border-top:1px solid #ddd">' + amountStr + '</td></tr>',
  '<tr><td style="padding:10px 14px;background:#f5f5f5"><strong>Booking ID</strong></td><td style="padding:10px 14px;border-left:1px solid #ddd;border-top:1px solid #ddd;font-size:12px;color:#888">' + bookingId + '</td></tr>',
  '</table>',
  '<p style="color:#999;font-size:12px;margin-top:16px">Client confirmation email sent automatically.</p>',
  '</div>'
].join('');

const arushiPayload = JSON.stringify({
  from: 'SoulSynergy Coaching <onboarding@resend.dev>',
  to: ['connect.sscoach@gmail.com'],
  subject: '\uD83D\uDCC5 New booking: ' + fullName + ' — ' + service + ' on ' + date,
  html: arushiHtml
});

return [{
  json: {
    // SQL-safe (single quotes escaped)
    first_name:      esc(firstName),
    last_name:       esc(lastName),
    email:           esc(clientEmail),
    // Raw (for reference)
    raw_first_name:  firstName,
    raw_email:       clientEmail,
    booking_id:      bookingId,
    // Pre-built email payloads
    client_payload:  clientPayload,
    arushi_payload:  arushiPayload
  }
}];
